

import { num } from '../../knobs'
import { clear, strokeOutline, wrapLoop } from '../common'

// Penrose P3 — Thin + Thick Rhombs, substitution method.
// Inflate from a central thick rhombus N times, collect tile polygons.
// Animate: substitution-depth stagger fade-in + slow global rotation (phason spin).

const PARAMS          = [
  { key: 'depth', type: 'int', min: 2, max: 6, default: 5, label: 'substitution depth' },
  { key: 'tileScale', type: 'range', min: 20, max: 150, default: 70, step: 5, label: 'tile scale' },
  { key: 'spin', type: 'range', min: 0, max: 0.5, default: 0.05, step: 0.01, label: 'rotation speed' },
  { key: 'fillOpacity', type: 'range', min: 0, max: 1, default: 0.18, step: 0.02, label: 'fill opacity' },
]

const PHI = (1 + Math.sqrt(5)) / 2

// Penrose P3 substitution rules (Robinson triangles decomposition).
// Each tile stored as { type: 'thick'|'thin', verts: [p0,p1,p2,p3], depth }
// We use the standard deflation on acute golden gnomons:
//   thick rhombus → 2 thick + 1 thin
//   thin rhombus  → 1 thick + 1 thin




function add(a    , b    )     { return [a[0] + b[0], a[1] + b[1]] }
function sub(a    , b    )     { return [a[0] - b[0], a[1] - b[1]] }
function scale(a    , s        )     { return [a[0] * s, a[1] * s] }
function lerp(a    , b    , t        )     { return add(scale(a, 1 - t), scale(b, t)) }

// Deflate one rhomb into smaller rhombs.
// thick: vertices p0(center), p1, p2(tip), p3 (diamond arrangement)
// We use a standard orientation: p0=bottom, p1=right, p2=top, p3=left
function deflateTile(tile           )              {
  const { type, verts: [p0, p1, p2, p3], depth } = tile
  const nd = depth + 1
  const inv = 1 / PHI

  if (type === 'thick') {
    // Split thick rhombus into 2 thick + 1 thin
    // Standard subdivision: point Q divides p0->p2 at 1/phi from p0
    // point R divides p1->p2 at 1/phi from p1
    const q = lerp(p0, p2, inv)
    const r = lerp(p1, p2, inv)
    return [
      { type: 'thick', verts: [r, p2, q, p1], depth: nd },   // top thick
      { type: 'thick', verts: [p1, q, p3, p0], depth: nd },  // bottom thick
      { type: 'thin',  verts: [p3, q, r, p1],  depth: nd },  // middle thin
    ]
  } else {
    // Split thin rhombus into 1 thick + 1 thin
    const q = lerp(p0, p1, inv)
    return [
      { type: 'thin',  verts: [q, p1, p2, p3],  depth: nd },
      { type: 'thick', verts: [p3, p2, p0, q],  depth: nd },
    ]
  }
}

function buildPenrose(depth        , edgeLen        )              {
  // Start: a ring of 10 thick rhombs in a decagon (standard seed)
  const tiles              = []
  const r = edgeLen
  for (let k = 0; k < 10; k++) {
    const ang = (k * Math.PI) / 5
    const ang2 = ((k + 1) * Math.PI) / 5
    const ang3 = ((k + 0.5) * Math.PI) / 5
    const p0     = [0, 0]
    const p1     = [r * Math.cos(ang), r * Math.sin(ang)]
    const p2     = [r * PHI * Math.cos(ang3), r * PHI * Math.sin(ang3)]
    const p3     = [r * Math.cos(ang2), r * Math.sin(ang2)]
    tiles.push({ type: 'thick', verts: [p0, p1, p2, p3], depth: 0 })
  }

  let current = tiles
  for (let d = 0; d < depth; d++) {
    const next              = []
    for (const t of current) next.push(...deflateTile(t))
    current = next
  }
  return current
}

function drawRhomb(ctx                          , tile           , fillAlpha        ) {
  const [p0, p1, p2, p3] = tile.verts
  ctx.beginPath()
  ctx.moveTo(p0[0], p0[1])
  ctx.lineTo(p1[0], p1[1])
  ctx.lineTo(p2[0], p2[1])
  ctx.lineTo(p3[0], p3[1])
  ctx.closePath()
  ctx.fillStyle = tile.type === 'thick'
    ? `rgba(200,170,100,${fillAlpha})`
    : `rgba(100,170,210,${fillAlpha})`
  ctx.fill()
  ctx.strokeStyle = tile.type === 'thick'
    ? `rgba(220,190,120,0.55)`
    : `rgba(120,190,230,0.55)`
  ctx.lineWidth = 0.7
  ctx.stroke()
}

export const r2_tile_05_penrose            = {
  id: 'r2-tile-05-penrose',
  name: 'PENROSE P3 RHOMBS',
  repo: 'Penrose 1974; Robinson triangle deflation',
  summary: 'Thin + thick golden-ratio rhombs generated by substitution deflation from a decagonal seed; depth layers stagger-fade in over a 4s cycle while the tiling slowly rotates inside the SDF mask.',
  helps: 'The golden-ratio proportions of Penrose rhombs harmonize with Gullhamrar glyph structure; five-fold symmetry is visually distinct from all other round2 prototypes.',
  params: PARAMS,
  init({ ctx, sdf, W, H, params, clock }) {
    let cachedTiles              = []
    let cachedDepth = 0
    let cachedScale = 0

    return wrapLoop(() => {
      const t = clock.nowSeconds()
      const depth = Math.max(2, Math.round(num(params, 'depth', 5)))
      const tileScale = num(params, 'tileScale', 70)
      const spin = num(params, 'spin', 0.05)
      const fillOpacity = num(params, 'fillOpacity', 0.18)

      if (depth !== cachedDepth || tileScale !== cachedScale) {
        cachedTiles = buildPenrose(depth, tileScale)
        cachedDepth = depth
        cachedScale = tileScale
      }

      clear(ctx, W, H)

      const maxDepth = Math.max(...cachedTiles.map(ti => ti.depth), 1)
      const rotation = t * spin * 0.3

      // Depth-reveal cycle
      const cycle = 4.5
      const phase = (t % cycle) / cycle

      ctx.save()
      ctx.translate(W / 2, H / 2)
      ctx.rotate(rotation)

      for (const tile of cachedTiles) {
        // Centroid for SDF test
        const cx = (tile.verts[0][0] + tile.verts[1][0] + tile.verts[2][0] + tile.verts[3][0]) / 4
        const cy = (tile.verts[0][1] + tile.verts[1][1] + tile.verts[2][1] + tile.verts[3][1]) / 4
        // Transform back to canvas space for SDF
        const cos = Math.cos(-rotation), sin = Math.sin(-rotation)
        const canvX = cx * cos - cy * sin + W / 2
        const canvY = cx * sin + cy * cos + H / 2
        const sx = (canvX / W) * sdf.w
        const sy = (canvY / H) * sdf.h
        if (sdf.sample(sx, sy) > tileScale * 0.3) continue

        const depthFrac = tile.depth / maxDepth
        const fadeStart = depthFrac * 0.65
        const fadeIn = Math.max(0, Math.min(1, (phase - fadeStart) / 0.2))

        drawRhomb(ctx, tile, fillOpacity * fadeIn)
      }

      ctx.restore()
      strokeOutline(ctx, sdf, W, H)
    })
  },
}
